/*
This rule is automatically generated by Custom Rules migration tool.
This is going to be a rule for AssignMeToTaskIfTaskStateWasChangedToInprogress #6 (Assign a Task to the Person who started it).
*/

const api = context.getService("targetprocess/api/v2");

async function getInProgressStates(entityType, entityId) {
  const states = await api.getByIdAsync(entityType, entityId, { select: `Project.Process.EntityStates.Where(EntityType.Name="${entityType}" and IsFinal=false).OrderBy(NumericPriority).Select({Id,IsInitial,IsPlanned})` });
  let precedingToWipIndex = states.findIndex(s => s.isPlanned);
  if (precedingToWipIndex < 0) {
    precedingToWipIndex = states.findIndex(s => s.isInitial);
  }

  return states.slice(precedingToWipIndex + 1);
}

async function entityIsInProgress() {
  const inProgressStates = await getInProgressStates(args.ResourceType, args.ResourceId);
  return inProgressStates.map(x => x.id).includes(args.Current.EntityState.Id);
}

async function entityHasAssignedUser() {
  const count = await api.getByIdAsync(args.ResourceType, args.ResourceId, { select: 'AssignedUser.Count()' });
  return count > 0;
}

async function getDeveloperRole() {
  const developerRoles = await api.getByIdAsync(args.ResourceType, args.ResourceId, { select: `Project.Process.EntityStates.Where(EntityType.Name="${args.ResourceType}").Select(Role).Where(Name="Developer")` });
  return developerRoles[0];
}

const [taskIsInProgress, hasUser, developerRole] = await Promise.all([entityIsInProgress(), entityHasAssignedUser(), getDeveloperRole()]);

if (!taskIsInProgress || hasUser || !developerRole) {
  return;
}

return {
  command: "targetprocess:CreateResource",
  payload: {
    resourceType: "Assignment",
    fields: {
      GeneralUser: {
        Id: args.Author.Id
      },
      Assignable: {
        Id: args.ResourceId
      },
      Role: {
        Id: developerRole.id
      }
    }
  }
};

/*
This rule is automatically generated by Custom Rules migration tool.
This is going to be a rule for AssignFeatureToBugWhenBugUserStoryWasChanged #8 (Assign a User Story's Feature to a Bug).
*/

const api = context.getService("targetprocess/api/v2");
const bugId = args.ResourceId;

async function getFeatureIdOfUserStory() {
  return await api.getByIdAsync('Bug', bugId, { select: 'UserStory.Feature.Id' });
}

const bugFeatureId = args.Current.Feature?.Id;
const userStoryFeatureId = await getFeatureIdOfUserStory();
if (!userStoryFeatureId) {
  return;
}

const isFeatureSetOnCreate = args.Modification === "Created" && bugFeatureId && bugFeatureId !== userStoryFeatureId;
const isFeatureSetOnUpdate = args.Modification === "Updated" && args.ChangedFields.includes("Feature") && bugFeatureId !== userStoryFeatureId;
if (isFeatureSetOnCreate || isFeatureSetOnUpdate) {
  return;
}

return {
  command: 'targetprocess:UpdateResource',
  payload: {
    resourceType: 'Bug',
    resourceId: bugId,
    fields: {
      Feature: {
        Id: userStoryFeatureId
      }
    }
  }
};

/*
This rule is automatically generated by Custom Rules migration tool.
This is going to be a rule for AssignTeamToFeatureBugsAndUserStoriesWhenTeamWasChanged #10 (Assign the Feature's Team to all its children).
*/

const teamId = args.Current.Team.Id;
const select = collection => `${collection}.Where(assignedTeams.Count(team.id = ${teamId}) = 0).Select(id)`;

const api = context.getService("targetprocess/api/v2");
const features = await api.queryAsync("Feature", {
  select: `{ stories: ${select('UserStories')}, bugs: ${select('Bugs')} }`,
  where: "id = " + args.Current.Assignable.Id
});
if (!features.length) { return; }

const children = [...features[0].stories, ...features[0].bugs];

return children.map(id => {
  return {
    command: "targetprocess:CreateResource",
    payload: {
      resourceType: "TeamAssignment",
      fields: {
        Team: { Id: teamId },
        Assignable: { Id: id }
      }
    }
  }
});

const api = require("targetprocess/api/v2");

const rx = /((\d{4}-[01]\d-[0-3]\d)(T[0-2]\d:[0-5]\d:[0-5]\d))(\.\d{0,7})?(Z|([+-]([01]\d|2[0-3]):[0-5]\d))?$/;

const isAssignable = ["Release", "TeamIteration", "Iteration"]
  .every(x => x.toLowerCase() !== args.data.ResourceType.toLowerCase());

const startDate = isAssignable ? "PlannedStartDate" : "StartDate";
const endDate = isAssignable ? "PlannedEndDate" : "EndDate";

const response = Boolean(args.data.Current)
  ? [{
    id: args.data.Current.Id,
    startDate : args.data.Current[startDate],
    endDate : args.data.Current[endDate]
  }]
  : await api.queryAsync(args.data.ResourceType, {
    select: `{Id,StartDate:${startDate},EndDate:${endDate}}`,
    where: `${startDate}!=null and ${endDate}!=null and [${args.Parameters.cf}]=null`
  })

return response.map(x => {
  return {
    command: "targetprocess:UpdateResource",
    payload: {
      resourceType: args.data.ResourceType,
      resourceId: x.id,
      fields: {
        [args.Parameters.cf]: Boolean(x.startDate) && Boolean(x.endDate)
          ? workingDaysBetweenDates(parseStartDate(x.startDate), parseStartDate(x.endDate))
          : null
      }
    }
  }
})

function parseStartDate(input) {
  // Transform date from text to date
  return new Date(`${rx.exec(input)[2]}T00:00:00`);
}

function workingDaysBetweenDates(startDate/*d0*/, endDate/*d1*/) {
  /* Two working days and an sunday (not working day) */
  const holidays = [/*'2016-05-03', '2016-05-05', '2016-05-07'*/];
  /*let startDate = parseDate(d0);
  let endDate = parseDate(d1);*/

  // Validate input
  if (isNaN(startDate.valueOf()) || isNaN(endDate.valueOf()) || endDate < startDate) {
    return 0;
  }

  // Calculate days between dates
  const millisecondsPerDay = 86400 * 1000; // Day in milliseconds
  let diff = (endDate - startDate);  // Milliseconds between datetime objects
  let days = diff / millisecondsPerDay + 1;

  // Subtract two weekend days for every week in between
  let weeks = Math.floor(days / 7);
  days -= weeks * 2;

  // Handle special cases
  let startDay = startDate.getDay();
  let endDay = endDate.getDay();

  // Remove weekend not previously removed.
  if (startDay - endDay > 1) {
    days -= 2;
  }
  // Remove start day if span starts on Sunday but ends before Saturday
  if (startDay == 0 && endDay != 6) {
    days--;
  }
  // Remove end day if span ends on Saturday but starts after Sunday
  if (endDay == 6 && startDay != 0) {
    days--;
  }
  /* Here is the  holidays code */
  //holidays.forEach(day => {
  //  if ((day >= d0) && (day <= d1)) {
  //    /* If it is not saturday (6) or sunday (0), substract it */
  //    if ((parseDate(day).getDay() % 6) != 0) {
  //      days--;
  //    }
  //  }
  //});
  return days;
}

