const epicId = args.Current.Epic.Id;
const AgileReleaseTrainId = args.Current.AgileReleaseTrain.Id;
const entityType = "Epic";
const parentSelect = "portfolioEpic.id";
const parentName = "PortfolioEpic";
const parentFilter = "PortfolioEpic.Epics.Count(id==" + epicId + ")>0";

const api = context.getService("targetprocess/api/v2");
let parents = null;
let querySpec = null;

//AgileReleaseTrain was assigned
if (args.Modification === "Created") {
  //Check if there is a parent where this AgileReleaseTrain is not assigned
  parents = await api.queryAsync(entityType, {
    select: parentSelect,
    where: `(id==${epicId} and ${parentName}.PortfolioEpicAgileReleaseTrains.Count(AgileReleaseTrain.Id==${AgileReleaseTrainId})=0)`
  });

  if (!parents || !parents[0]) {
    return;
  }

  //Assign this AgileReleaseTrain to the parent
  return {
    command: "targetprocess:CreateResource",
    payload: {
      resourceType: "PortfolioEpicAgileReleaseTrain",
      fields: {
        AgileReleaseTrain: { Id: AgileReleaseTrainId },
        portfolioEpic: { Id: parents[0] }
      }
    }
  };
}

//AgileReleaseTrain was unassigned

//Check if there is a parent where this AgileReleaseTrain is assigned
parents = await api.queryAsync(entityType, {
  select: parentSelect,
  where: `id=${epicId} and ${parentName}.PortfolioEpicAgileReleaseTrains.Count(AgileReleaseTrain.Id==${AgileReleaseTrainId})>0`
});
if (!parents || !parents[0]) {
  return;
}

//Check if there are other children with this AgileReleaseTrain
const count = await api.queryAsync(entityType, {
  where: `(id!=${epicId} and ${parentFilter} and EpicAgileReleaseTrains.Count(AgileReleaseTrain.Id==${AgileReleaseTrainId})>0)`,
  result: "count"
});
if (count > 0) {
  return;
}

//There is no other children with this AgileReleaseTrain
const ids = await api.queryAsync("PortfolioEpicAgileReleaseTrain", {
  select: "id",
  where: "AgileReleaseTrain.id == " + AgileReleaseTrainId + " and portfolioEpic.id == " + parents[0]
});

//Unassign this Team from its parent
return {
  command: "targetprocess:DeleteResource",
  payload: {
    resourceType: "PortfolioEpicAgileReleaseTrain",
    resourceId: ids[0]
  }
};

