function parseDate(input) {// Transform date from text to date
  const rx = /(\d{4}-[01]\d-[0-3]\d)(T[0-2]\d:[0-5]\d:[0-5]\d)(\.\d+)?([+-][0-2]\d:[0-5]\d|Z)/;
  return rx.exec(input)[1];
}
function addWeek(startDate, limit, createDate, arr, bannedList, options = { month: args.Current, number: undefined }) {
  const weekStart = parseDate(startDate.toISOString());
  const number = options.number;
  if (!bannedList.includes(weekStart)) {
    const [monthName, year] = new Intl.DateTimeFormat('en-EN', { month: 'short', year: 'numeric' }).format(new Date(weekStart)).split(" ");
    const name = options.number ? ([year, monthName, correctDateNum(startDate.getDate())].join("-") + " / Week " + number) : getName(startDate);
    const out = {
      Name: name,
      CreateDate: createDate.toISOString().slice(0, -1),
      PlannedStartDate: weekStart + "T00:00:00.000",
      PlannedEndDate: parseDate(utils.addDays(startDate, 6).toISOString()) + "T23:59:59.999"
    }
    if (options.number) { out[options.month.ResourceType] = { Id: options.month.Id } }
    arr.push(utils.createResource("WeekPeriod", out))
    const nextMonday = utils.addDays(startDate, 7);
    if (nextMonday.getTime() <= limit) {
      addWeek(nextMonday, limit, createDate, arr, bannedList, options = { month: args.Current, number: number?(number+1):undefined })
    }
  }
}
//standart logic
function getName(date) {
  const year = date.getFullYear();
  if (date.getMonth() === 11 && date.getDate() > 28) { return `${year + 1} / Week 01` }
  const firstJan = new Date(year, 0, 1);
  let firstJanDay = (firstJan.getDay() || 7) - weekStart + 1;
  if (firstJanDay <= 0) { firstJanDay += 7 }
  const dif = utils.differenceInWeeks(date, firstJan) + 1 + Number(1 < firstJanDay && firstJanDay < 5);
  return `${year} / Week ${correctDateNum(dif)}`
}
//retail logic
function firstWeekDay(year, month, day, targetDayOfWeek) {
  const monthNumber = correctDateNum(month);
  const dayNumber = correctDateNum(day);
  const dateString = `${year}-${monthNumber}-${dayNumber}T00:00:00.000`;
  const output = new Date(dateString);
  const dayOfWeek = output.getDay() || 7;
  let dif = targetDayOfWeek - dayOfWeek;
  if (dif > 0) { dif -= 7; }
  output.setHours((24 * dif) - (output.getTimezoneOffset() / 60));
  return output
}

