//FUNCS
function addRetailYear(yearNumber, yearStart, yearEnd, endDayOffset, iteration, now, weeksDistribution, commandsList, fyShift, monthNames) {//year retail
  const yearName = createYearName(yearPrefix, yearPostfix, yearNumber);
  const normalLength = (utils.differenceInWeeks(yearEnd, yearStart) + 1) === 52;
  let i = iteration * createDatesDif;
  const yearCreateDate = parseDate(utils.addSeconds(now, i).toISOString());
  const quarters = addRetailQuarters(yearStart, yearNumber, yearCreateDate, endDayOffset, normalLength, weeksDistribution, monthNames);
  return {
    Name: yearName,
    PlannedStartDate: dateToStrig(yearStart),
    PlannedEndDate: dateToStrig(yearEnd),
    CreateDate: yearCreateDate,
    QuarterPeriods: { Items: quarters }
  }
}
function addRetailQuarters(yStart, yName, yCreateDate, endDayOffset, yLengthNormal, weeksDistribution, monthNames) {//quarter retail
  const out = [];
  let createDate = new Date(yCreateDate);
  let daysSum = 7 * weeksDistribution[0] - 1;
  const mInfo = [{ start: 0, end: +daysSum + endDayOffset }];
  for (let i = 1; i < weeksDistribution.length; i++) {
    mInfo.push({ start: daysSum + 1, end: (daysSum += (weeksDistribution[i] * 7)) + endDayOffset });
  }
  const qInfo = [
    { start: 0, end: 90 + endDayOffset, mInfo: mInfo },
    { start: 91, end: 181 + endDayOffset, mInfo: mInfo },
    { start: 182, end: 272 + endDayOffset, mInfo: mInfo },
    yLengthNormal ?
      { start: 273, end: 363 + endDayOffset, mInfo: mInfo }
      :
      { start: 273, end: 370 + endDayOffset, mInfo: [...mInfo.slice(0, 2), { start: mInfo[2].start, end: mInfo[2].end + 7 }] },
  ];
  for (let i in qInfo) {
    const qName = yName + " Q" + (+i + 1);
    const qStart = utils.addDays(yStart, qInfo[i].start);
    const qEnd = utils.addDays(yStart, qInfo[i].end);
    const qCreateDate = parseDate(createDate.toISOString());
    createDate = utils.addSeconds(createDate, 105);
    const months = addRetailMonths(qStart, qCreateDate, 3 * (+i), qInfo[i].mInfo, monthNames);
    out.push({
      Name: qName,
      PlannedStartDate: dateToStrig(qStart),
      PlannedEndDate: dateToStrig(qEnd),
      CreateDate: qCreateDate,
      MonthPeriods: { Items: months }
    })
  }
  return out
}
function addRetailMonths(qStart, qCreateDate, initialIndex, mInfo, monthNames) {//months retail
  let createDate = new Date(qCreateDate);
  let index = initialIndex;
  const out = [];
  for (let i in mInfo) {
    const mStart = utils.addDays(qStart, mInfo[i].start);
    const mEnd = utils.addDays(qStart, mInfo[i].end);
    const year = mStart.getFullYear().toString();
    const mName = year + "-" + monthNames[index++];
    const mCreateDate = parseDate(createDate.toISOString());
    createDate = utils.addSeconds(createDate, 35);
    out.push({
      Name: mName,
      PlannedStartDate: dateToStrig(mStart),
      PlannedEndDate: dateToStrig(mEnd),
      CreateDate: mCreateDate
    })
  }
  return out;
}
//common funcs
function dateToStrig(date) {
  return date.toISOString().slice(0, -1);
}
function correctDateNum(num) {
  return num < 10 ? "0" + num : num.toString();
}
function firstWeekDay(year, month, day, targetDayOfWeek) {
  const monthNumber = correctDateNum(month);
  const dayNumber = correctDateNum(day);
  const dateString = `${year}-${monthNumber}-${dayNumber}T00:00:00.000`;
  const output = new Date(dateString);
  const dayOfWeek = output.getDay() || 7;
  let dif = targetDayOfWeek - dayOfWeek;
  if (dif > 0) { dif -= 7; }
  output.setHours((24 * dif) - (output.getTimezoneOffset() / 60));
  return output
}
function parseDate(input) {// Transform date from text to date
  const rx = /(\d{4}-[01]\d-[0-3]\d)(T[0-2]\d:[0-5]\d:[0-5]\d)(\.\d+)?([+-][0-2]\d:[0-5]\d|Z)/;
  const out = rx.exec(input);
  return out[1] + out[2];
}
function generator(name, dates, createDate) {
  return {
    Name: name,
    PlannedStartDate: new Date(dates[0].setHours(0, 0, 0)).toISOString().slice(0, -1),
    PlannedEndDate: new Date(dates[1].setHours(23, 59, 59)).toISOString().slice(0, -1),
    CreateDate: createDate
  };
}
function createYearName(prefix, postfix, yearNum) { return prefix + yearNum + postfix }
function main(iteration, lastStartDate, now, startMonth, bannedList, commandsList) {
  const yearDates = addYear(lastStartDate, startMonth, iteration);
  if (bannedList.includes(parseDate(yearDates[0].toISOString()))) { return }
  let i = iteration * createDatesDif;
  const yearName = createYearName(yearPrefix, yearPostfix, yearDates[0].getFullYear() + yearShiftInc);
  const yearItems = [];
  const yearCreateDate = parseDate(utils.addSeconds(now, i).toISOString());
  const year = generator(yearName, yearDates, yearCreateDate);
  for (let j = 0; j < 4; j++) {
    const quarterDates = addQuarter(yearDates[0], j);
    const quarterName = yearName + " Q" + (j + 1);
    const quarterItems = [];
    const quarterCreateDate = parseDate(utils.addSeconds(now, ++i).toISOString());
    const quarter = generator(quarterName, quarterDates, quarterCreateDate);
    for (let k = 0; k < 3; k++) {
      const monthDates = addMonths(quarterDates[0], k);
      const monthName = getMonthName(monthDates[0]);
      i += 32;
      const monthCreateDate = parseDate(utils.addSeconds(now, i).toISOString());
      quarterItems.push(generator(monthName, monthDates, monthCreateDate));
    }
    quarter["MonthPeriods"] = { Items: quarterItems };
    yearItems.push(quarter)
  }
  year["QuarterPeriods"] = { Items: yearItems }
  commandsList.push(utils.createResource("YearPeriod", year));
}
function getYearStartDate(year, month) {//calendar years
  return new Date(year, month, 1);
}
function addYear(date, startMonth, iter = 1) {
  return [
    new Date(date.getFullYear() + iter, startMonth, 1),
    new Date(date.getFullYear() + iter + 1, startMonth, 0)
  ];
}
function addQuarter(date, iter = 1) {//calendar quarters
  return [
    new Date(utils.addMonths(date, 3 * iter)),
    new Date(new Date(utils.addMonths(date, 3 * iter + 3)).setDate(0))
  ];
}
function addMonths(date, iter = 1) {//calendar months
  return [utils.addMonths(date, iter), new Date(utils.addMonths(date, iter + 1).setDate(0))];
}
function getMonthName(date) {
  const month = date.getMonth();
  return date.getFullYear() + '-' + correctDateNum(month + 1);
}

