  }
  if (!isStartDate(startDate)) {
    throw new Error(`"${startDate.toISOString().slice(0, -1)}" is not a valid start date.`);
  }
  if (!isStartDate(endDate) && !isEndDate(endDate)) {
    throw new Error(`Date "${endDate.toISOString().slice(0, -1)}" is not a valid start date or end date.`);
  }
  // Calculate days between dates
  const millisecondsPerDay = 86400 * 1000; // Day in milliseconds
  let diff = endDate.valueOf() - startDate.valueOf() + (isEndDate(endDate) ? 1000 : millisecondsPerDay); // Milliseconds between datetime objects
