function binarySearch(arr, jobProfile) {
  let min = 0,
    max = arr.length - 1,
    guess;

  while (min <= max) {
    guess = Math.floor((min + max) / 2);

    if (arr[guess] === jobProfile) {
      return arr[guess];
    } else {
      if (arr[guess] < jobProfile) {
        min = guess + 1;
      } else {
        max = guess - 1;
      }
    }
  }
  return null;
}

