function periodWrapper(source, takeLastOverlappingPeriod = false) {
  // Get the Iterator prototype, which has no global name
  const itPrototype = Object.getPrototypeOf(Object.getPrototypeOf([][Symbol.iterator]()));
  // Allow source to be an iterable or an iterator
  if (Symbol.iterator in source) {
    source = source[Symbol.iterator]();
  }
  // Create our wrapper iterator
  const it = Object.create(itPrototype);
  // Remember the last value we saw from `next`
  const getPeriod = period => {
    return period
      ? {
          startDate: parseStartDate(period.plannedStartDate),
          endDate: period.plannedEndDate ? parseEndDate(period.plannedEndDate) : undefined
        }
      : undefined;
  };
  let current = null;
  let next = source.next();
  let currentPeriod = null;
  let nextPeriod = getPeriod(next.value);
  const moveNext = () => {
    current = next;
    currentPeriod = nextPeriod;
    next = source.next();
    nextPeriod = getPeriod(next.value);
  };
  // The iterator method
  it.next = () => {
    moveNext();
    if (takeLastOverlappingPeriod) {
      while (!next.done && currentPeriod.startDate.valueOf() === nextPeriod.startDate.valueOf()) {
        moveNext();
      }
      if (!next.done && (!currentPeriod.endDate || currentPeriod.endDate.valueOf() > nextPeriod.startDate.valueOf())) {
        currentPeriod.endDate = new Date(nextPeriod.startDate.getTime() - 1000);
      }
    }
    return current;
  };
  // Our additional methods
  it.currentValue = () => current && current.value;
  it.nextValue = () => next && next.value;
  it.currentPeriod = () => currentPeriod;
  it.nextPeriod = () => nextPeriod;
  return it;
}

