}
function getMaxDate(dates) {
  return dates.reduce(function (a, b) {
    return a.valueOf() > b.valueOf() ? a : b;
  });
}
function getMinDate(dates) {
  return dates.reduce(function (a, b) {
    return a.valueOf() < b.valueOf() ? a : b;
  });
}
function isStartDate(date) {
  return date.getHours() === 0 && date.getMinutes() === 0 && date.getSeconds() === 0 && date.getMilliseconds() === 0;
}
function isEndDate(date) {
  return date.getHours() === 23 && date.getMinutes() === 59 && date.getSeconds() === 59 && date.getMilliseconds() === 0;
}
function workingDaysBetweenDates(startDate, endDate) {
  // Validate input
  if (isNaN(startDate.valueOf()) || isNaN(endDate.valueOf()) || endDate.valueOf() < startDate.valueOf()) {
    return 0;
  }
  if (!isStartDate(startDate)) {
    throw new Error(`"${startDate.toISOString().slice(0, -1)}" is not a valid start date.`);
  }
  if (!isStartDate(endDate) && !isEndDate(endDate)) {
    throw new Error(`Date "${endDate.toISOString().slice(0, -1)}" is not a valid start date or end date.`);
  }
  // Calculate days between dates
  const millisecondsPerDay = 86400 * 1000; // Day in milliseconds
  let diff = endDate.valueOf() - startDate.valueOf() + (isEndDate(endDate) ? 1000 : millisecondsPerDay); // Milliseconds between datetime objects
  let days = diff / millisecondsPerDay;
  // Subtract two weekend days for every week in between
  let weeks = Math.floor(days / 7);
  days -= weeks * 2;
  // Handle special cases
  let startDay = startDate.getDay();
  let endDay = endDate.getDay();
  // Remove weekend not previously removed.
  if (startDay - endDay > 1) {
    days -= 2;
  }
  // Remove start day if span starts on Sunday but ends before Saturday
  if (startDay == 0 && endDay != 6) {
    days--;
  }
  // Remove end day if span ends on Saturday but starts after Sunday
  if (endDay == 6 && startDay != 0) {
    days--;
  }
  /* Here is the  holidays code */
