  if (entity.ResourceType === 'WorkAllocation') {
    additionalFields.push(
      `WorkAllocationTimeFrames:WorkAllocation${args.Parameters.periodType}s.Select({Id,TimeFrame:${args.Parameters.periodType}.Id,${args.Parameters.periodType}.PlannedStartDate,${args.Parameters.periodType}.PlannedEndDate}).OrderBy(PlannedStartDate).Select({Id,TimeFrame,PlannedStartDate,PlannedEndDate})`
    );
  }
  return getResourceData(entity, additionalFields);
}
function getResourceData(entity, additionalFields = []) {
  if (entity.ResourceType === 'WorkAllocation') {
    return api.getByIdAsync(entity.ResourceType, entity.ResourceId, {
      select: getQueryString(getQueryFields(workAllocationQueryFields).concat(additionalFields))
