  const roundDelta = Object.assign({['Reserved Hours']: 0}, useMD ? {['Reserved MD']: 0} : {});
  const obsoleteDemands = [];
  const obsoleteResourcePeriods = [];
  const resourcePeriods = [];
  const demands = [];
  const processDemand = function (start, period, timeFrame) {
    if (start.valueOf() >= period.startDate.valueOf() && start.valueOf() < period.endDate.valueOf()) {
      const demandStartDate = getMaxDate([period.startDate, startDate]);
      const demandEndDate = getMinDate([period.endDate, endDate]);
