      demands.push(demand);
    }
  };
  console.log("here", totalHours )
  let start = startDate;
  while (periodsIterator.next().value && start.valueOf() < endDate.valueOf()) {
    const nextStart = new Date(periodsIterator.currentPeriod().endDate.valueOf() + 1000);
    if (periodsIterator.currentValue()) {
      processDemand(start, periodsIterator.currentPeriod(), periodsIterator.currentValue());
      while (
        resourcePeriodsIterator.nextValue() &&
