      }
      if (start.valueOf() >= periodsIterator.currentPeriod().startDate.valueOf()) {
        if (
          !resourcePeriodsIterator.nextValue() ||
          resourcePeriodsIterator.nextPeriod().startDate.valueOf() !==
            periodsIterator.currentPeriod().startDate.valueOf()
        ) {
          resourcePeriods.push(periodsIterator.currentValue().id);
        }
        while (
          resourcePeriodsIterator.nextValue() &&
          nextStart.valueOf() > resourcePeriodsIterator.nextPeriod().startDate.valueOf()
        ) {
          resourcePeriodsIterator.next();
        }
        while (periodsIterator.nextValue() && nextStart.valueOf() > periodsIterator.nextPeriod().startDate.valueOf()) {
          periodsIterator.next();
        }
      }
      if (resourcePeriodsIterator.nextValue() && nextStart.valueOf() > endDate.valueOf()) {
        while (resourcePeriodsIterator.next().value) {
          obsoleteResourcePeriods.push(resourcePeriodsIterator.currentValue().id);
        }
      }
    }
    start = nextStart;
