  while (demandsIterator.next().value) {
    obsoleteDemands.push(demandsIterator.currentValue().id);
  }
  /* @ts-ignore */
  return [{
    command: 'targetprocess:UpdateResource',
    payload: {
      resourceType: resource.resourceType,
      resourceId: resource.id,
