    return {
      command: 'targetprocess:DeleteResource',
      payload: {
        resourceType: `Demand`,
        resourceId: x,
        fields: undefined
      }
    };
  }));
}
function addOrUpdateDemand(name, resource, users, startDate, endDate, timeFrame, ratio, percentage, roundDelta, demand = undefined) {
  const isTimeOff = timeOffEntities.some(x => x.toLowerCase() === resource.resourceType.toLowerCase());
  const useMD = args.Parameters.capacityUnit === 'Man Days';
  const daysData = new DaysDataCollector(startDate, endDate, users).daysData;
  console.log("daysData",daysData, users)
  const totalHours = getTotalHours(resource, daysData.dailyValues, isTimeOff, users.length === 0);
  const totalMD = useMD ? getTotalMDs(resource, daysData.dailyValues, isTimeOff, users.length === 0) : undefined;
  const reservedHours = fixupRoundDelta((totalHours || 0) * ratio, roundDelta, 'Reserved Hours');
  const reservedMD = useMD
    ? fixupRoundDelta((totalMD || 0) * ratio, roundDelta, 'Reserved MD')
    : undefined;
  return Object.assign(
    demand ? {Id: demand.id} : {},
    {Name: `${timeFrame.name} / ${name}${typeof percentage === 'number' ? ` / ${percentage}%` : ''}`},
    args.Parameters.useUsers || isTimeOff
      ? {ConnectedUser: resource.connectedUser ? {Id: resource.connectedUser.id} : null}
      : {},
    args.Parameters.useTeams && !isTimeOff
      ? {ConnectedTeam: resource.connectedTeam ? {Id: resource.connectedTeam.id} : null}
      : {},
    args.Parameters.useArts && !isTimeOff
      ? {AgileReleaseTrain: resource.agileReleaseTrain ? {Id: resource.agileReleaseTrain.id} : null}
      : {},
    {
      [args.Parameters.periodType]: {Id: timeFrame.id},
      PlannedStartDate: `${startDate.toISOString().split('T')[0]}T00:00:00`,
      PlannedEndDate: `${endDate.toISOString().split('T')[0]}T23:59:59`
    },
    {['Reserved Capacity']: percentage},
    {['Total Hours']: totalHours, ['Reserved Hours']: reservedHours},
    useMD ? {['Total MD']: totalMD, ['Reserved MD']: reservedMD} : {}
  );
}
function getRatio(resource, isPercentage, isTimeOff, useMD, totalHours, totalMD) {
  return isTimeOff
    ? typeof resource.partialLeave === 'number' && resource.partialLeave > 0 && resource.partialLeave <= 1 ? resource.partialLeave : 1
    : isPercentage
      ? resource.percentage / 100
      : useMD
        ? totalMD ? resource.reservedMD / totalMD : null
        : totalHours ? resource.reservedHours / totalHours : null;
}
function getTotalMDs(resource, dailyValues, isTimeOff, useDefault = false) {
  return getTotalValue(resource, dailyValues.dailyMDs, dailyValues.workingDays, 1, isTimeOff, useDefault);
}
function getTotalHours(resource, dailyValues, isTimeOff, useDefault = false) {
  return getTotalValue(resource, dailyValues.dailyHours, dailyValues.workingDays, 8, isTimeOff, useDefault);
}
function getTotalValue(resource, dailyValue, workingDays, k, isTimeOff, useDefault = false) {
  return useDefault
    ? isTimeOff
      ? 0
      : getDefaultTotalValue(resource, workingDays, k)
    : Math.round(dailyValue * 100) / 100;
}
function getDefaultTotalValue(resource, workingDays, k) {
  return workingDays * k * (resource.allocationType === 'Team' ? args.Parameters.avgPeopleInTeam : 1);
}
function fixupRoundDelta(value, roundDelta, requestedProp) {
  let valueWithDelta = value + roundDelta[requestedProp];
  const requestedValue = Math.round(valueWithDelta * 100) / 100;
  roundDelta[requestedProp] = valueWithDelta - requestedValue;
  return requestedValue;
}

