// Fetch up all of the allocations for the project
const allocations = await api.queryAsync("WorkAllocation", {
  select: "{id, name, percentage}",
  where: "traditionalProject.id= " + traditionalProjectId,
});
//console.log(allocations);

// Create an 'in' clause containing the allocation IDs 
// we are interested in and make a map of the percentages
// so we can use them to build the new demand name.
const commands = [];
if (allocations.length > 0) {
  const allocMap = new Map();
  var allocInClause = "[";
  allocations.forEach((alloc) => {
    allocInClause += alloc.id + ',';
    allocMap.set(alloc.id, alloc.percentage);
  })
  allocInClause = allocInClause.slice(0, -1) + "]";
  //console.log(allocInClause);
  //console.log(allocMap);

  // Fetch up all of the demands for the allocations
  const demands = await api.queryAsync("Demand", {
    select: "{id, name, allocId:workAllocation.id, month:monthPeriod.name}",
    where: "WorkAllocation.id in " + allocInClause
  });
  //console.log(demands);

  // Let's build a list of the commands that will
  // update the work allocations first
  allocations.forEach((alloc) => {
    commands.push(utils.updateResource("WorkAllocation", alloc.id,
      {
        "Name": args.Current.Name + " / " + alloc.percentage + "%"
      }));
  })

  // Append the changes to all of the Demands as well
  demands.forEach((demand) => {
    const percentage = allocMap.get(demand.allocId);
    commands.push(utils.updateResource("Demand", demand.id,
      {
        "Name": demand.month + " / " + args.Current.Name + " / " + percentage + "%"
      }));
  })
}

